public class ETGTradingNotes extends common
{
    /// <summary>
    ///
    /// </summary>
    /// <param name = "_fieldId"></param>

}

Method.Source:
public void modifiedField(FieldId _fieldId)
{

    ETGNotes        eTgnotes;
    ETGTradingNotes tradingNotes;

    eTgnotes    = ETGNotes::find();

    super(_fieldId);
    if(_fieldId == fieldNum(ETGTradingNotes,EnumNotes))
    {
        select firstonly tradingNotes
            where tradingNotes.EnumNotes == this.EnumNotes
            && tradingNotes.RecId == this.RecId;

        if (tradingNotes)
        {
            throw error("@ETG_Labels:ETG_NotesExits");
        }

        switch(this.EnumNotes)
        {
            case ETGNote::Header :
                this.Description = eTgnotes.Header;
                break;

            case ETGNote::Title :
                this.Description = eTgnotes.Title;
                break;

            case ETGNote::Acceptance :
                this.Description = eTgnotes.Acceptance;
                break;

            case ETGNote::Arbitration :
                this.Description = eTgnotes.Arbitration;
                break;

            case ETGNote::Broker :
                this.Description = eTgnotes.Broker;
                break;

            case ETGNote::Confidentiality :
                this.Description = eTgnotes.Confidentiality;
                break;

            case ETGNote::Delivery :
                this.Description = eTgnotes.Delivery;
                break;

            case ETGNote::Documents :
                this.Description = eTgnotes.Documents;
                break;

            case ETGNote::ForceMajeure :
                this.Description = eTgnotes.ForceMajeure;
                break;

            case ETGNote::Insurance :
                this.Description = eTgnotes.Insurance;
                break;

            case ETGNote::LandedWeightSupervision :
                this.Description = eTgnotes.LandedWeightSupervision;
                break;

            case ETGNote::LicenseTaxation :
                this.Description = eTgnotes.LicenseTaxation;
                break;

            case ETGNote::NoObjection :
                this.Description = eTgnotes.NoObjection;
                break;

            case ETGNote::OtherConditions :
                this.Description = eTgnotes.OtherConditions;
                break;

            case ETGNote::WeightQualityAssesment :
                this.Description = eTgnotes.WeightQualityAssesment;
                break;

            case ETGNote::WeightSpecs :
                this.Description = eTgnotes.WeightSpecs;
                break;
        }
    }

}

/// <summary>
///
/// </summary>
public void initValue()
{
    ETGNotes    etgnotes;

    etgnotes    = ETGNotes::find();

    super();

    if(this.EnumNotes == ETGNote::Header)
    {
        this.Description = eTgnotes.Header;
    }

}

/// <summary>
///
/// </summary>
public void delete()
{
    ETGTradingNotes tradingNotes;
    super();

    delete_from tradingNotes
        where tradingNotes.EnumNotes == this.EnumNotes
        && tradingNotes.RecId == this.RecId;  
}
